     8→function getApiUrl(): string {
     9→  // In Electron, get URL directly from preload (available immediately)
    10→  if (typeof window !== 'undefined' && window.electronAPI?.server?.getApiUrl) {
    11→    return window.electronAPI.server.getApiUrl();
