    13→  // Fallback: use port from preload
    14→  if (typeof window !== 'undefined' && window.electronAPI?.server) {
    15→    const port = window.electronAPI.server.getPort();
    16→    return `http://localhost:${port}`;
    17→  }
    18→  // In browser/dev: use discovered port from store, or default
    19→  if (typeof window !== 'undefined') {
