    36→/** Probe ports 3333..3333+PORT_DISCOVERY_MAX and set store when server is found. Call when in browser dev. */
    37→export async function discoverServerPort(): Promise<number> {
    38→  for (let p = DEFAULT_SERVER_PORT; p < DEFAULT_SERVER_PORT + PORT_DISCOVERY_MAX; p++) {
    39→    try {
