   256→function createMasterStackLayout(widgets: LayoutWidgetInfo[]): LayoutNode {
   257→  if (widgets.length === 0) {
   258→    return {
   259→      type: 'leaf',
   260→      id: generateLayoutId(),
   261→      widgetType: 'tasks',
   262→      widgetId: 'tasks-widget',
   263→    };
   264→  }
   265→
   266→  if (widgets.length === 1) {
   267→    return {
   268→      type: 'leaf',
   269→      id: generateLayoutId(),
   270→      widgetType: widgets[0].type,
   271→      widgetId: widgets[0].id,
   272→    };
   273→  }
   274→
   275→  const [mainWidget, ...stackWidgets] = widgets;
   276→
   277→  const mainPanel: LayoutLeaf = {
   278→    type: 'leaf',
   279→    id: generateLayoutId(),
   280→    widgetType: mainWidget.type,
   281→    widgetId: mainWidget.id,
   282→  };
   283→
   284→  const stackPanels: LayoutLeaf[] = stackWidgets.map(w => ({
   285→    type: 'leaf',
   286→    id: generateLayoutId(),
   287→    widgetType: w.type,
   288→    widgetId: w.id,
   289→  }));
   290→
   291→  const stackGroup: LayoutGroup = {
   292→    type: 'group',
   293→    id: generateLayoutId(),
   294→    direction: 'vertical',
   295→    children: stackPanels,
   296→    sizes: stackPanels.map(() => 100 / stackPanels.length),
   297→  };
   298→
   299→  return {
   300→    type: 'group',
   301→    id: 'root',
   302→    direction: 'horizontal',
   303→    children: [mainPanel, stackGroup],
   304→    sizes: [65, 35],
   305→  };
   306→}
