   386→/**
   387→ * Create quad layout (2x2 grid) - uses first 4 widgets
   388→ * All widgets provided by caller - no auto-adding
   389→ */
   390→function createQuadLayout(widgets: LayoutWidgetInfo[]): LayoutNode {
   391→  // Use up to 4 widgets
   392→  const slots = widgets.slice(0, 4);
   393→
   394→  if (slots.length === 0) {
   395→    return {
   396→      type: 'leaf',
   397→      id: generateLayoutId(),
   398→      widgetType: 'tasks',
   399→      widgetId: 'tasks-widget',
   400→    };
   401→  }
   402→
   403→  if (slots.length === 1) {
   404→    return {
   405→      type: 'leaf',
   406→      id: generateLayoutId(),
   407→      widgetType: slots[0].type,
   408→      widgetId: slots[0].id,
   409→    };
   410→  }
   411→
   412→  // For 2-4 widgets, create appropriate grid
   413→  const createSlot = (idx: number): LayoutLeaf => ({
   414→    type: 'leaf',
   415→    id: generateLayoutId(),
   416→    widgetType: slots[idx].type,
   417→    widgetId: slots[idx].id,
   418→  });
   419→
   420→  if (slots.length === 2) {
   421→    // 2 widgets: side by side
   422→    return {
   423→      type: 'group',
   424→      id: 'root',
   425→      direction: 'horizontal',
   426→      children: [createSlot(0), createSlot(1)],
   427→      sizes: [50, 50],
   428→    };
   429→  }
   430→
   431→  if (slots.length === 3) {
   432→    // 3 widgets: 2 on top, 1 on bottom (centered or left-aligned)
   433→    const topRow: LayoutGroup = {
   434→      type: 'group',
   435→      id: generateLayoutId(),
   436→      direction: 'horizontal',
   437→      children: [createSlot(0), createSlot(1)],
   438→      sizes: [50, 50],
   439→    };
   440→
   441→    return {
   442→      type: 'group',
   443→      id: 'root',
   444→      direction: 'vertical',
   445→      children: [topRow, createSlot(2)],
   446→      sizes: [50, 50],
   447→    };
   448→  }
   449→
   450→  // 4 widgets: full 2x2 grid
   451→  const topRow: LayoutGroup = {
   452→    type: 'group',
   453→    id: generateLayoutId(),
   454→    direction: 'horizontal',
   455→    children: [createSlot(0), createSlot(1)],
   456→    sizes: [50, 50],
   457→  };
   458→
   459→  const bottomRow: LayoutGroup = {
   460→    type: 'group',
   461→    id: generateLayoutId(),
   462→    direction: 'horizontal',
   463→    children: [createSlot(2), createSlot(3)],
   464→    sizes: [50, 50],
   465→  };
   466→
   467→  return {
   468→    type: 'group',
   469→    id: 'root',
   470→    direction: 'vertical',
   471→    children: [topRow, bottomRow],
   472→    sizes: [50, 50],
   473→  };
   474→}
