   643→export const useWorkspaceStore = create<WorkspaceState>()((set, get) => ({
   644→  // Initial state
   645→  workspacePath: null,
   646→  agents: [],
   647→  consoles: [],
   648→  realTerminals: [],
   649→  planSteps: [],
   650→  focusedWidgetId: null,
   651→  focusedWidgetType: null,
   652→  maximizedWidgetId: null,
   653→  widgets: [],
   654→  showAgentStatus: false, // Hidden by default so ProjectStartingPoint shows first
   655→  tasksVisible: false, // Hidden by default so ProjectStartingPoint shows first
   656→  layoutTree: null,
   657→  navigateToView: null,
   658→  onCreateConsole: null,
   659→  onCreateTerminal: null,
   660→  onCreateTask: null,
   661→  onCloseConsole: null,
   662→  onMinimizeConsole: null,
   663→  onMaximizeConsole: null,
   664→  onRestoreConsole: null,
   665→  onClearConsole: null,
   666→
   667→  // Setters (called by Workspace.tsx to sync state)
   668→  setWorkspacePath: (path) => set({ workspacePath: path }),
   669→  setAgents: (agents) => set({ agents }),
   670→  setConsoles: (consoles) => set({ consoles }),
   671→  setRealTerminals: (terminals) => set({ realTerminals: terminals }),
   672→  setPlanSteps: (steps) => set({ planSteps: steps }),
   673→
   674→  // Focus management
   675→  setFocusedWidget: (id, type) => set({ focusedWidgetId: id, focusedWidgetType: type }),
   676→  setMaximizedWidget: (id) => set({ maximizedWidgetId: id }),
   677→  setWidgets: (widgets) => set({ widgets }),
   678→  setShowAgentStatus: (show) => set({ showAgentStatus: show }),
   679→  setTasksVisible: (visible) => set({ tasksVisible: visible }),
   680→
   681→  // Arrow key / shortcut navigation
   682→  moveFocus: (direction) => {
   683→    const { widgets, focusedWidgetId } = get();
   684→    if (widgets.length === 0) return;
   685→
   686→    // Helper to blur any active input and set focus
   687→    const blurAndSetFocus = (id: string, type: WidgetType) => {
   688→      // Blur any currently focused DOM element (e.g., text inputs) when navigating
   689→      if (document.activeElement instanceof HTMLElement) {
   690→        const tagName = document.activeElement.tagName;
   691→        if (tagName === 'INPUT' || tagName === 'TEXTAREA' || document.activeElement.isContentEditable) {
   692→          document.activeElement.blur();
   693→        }
   694→      }
   695→      set({ focusedWidgetId: id, focusedWidgetType: type });
   696→    };
   697→
   698→    // If nothing focused, focus the first widget
   699→    if (!focusedWidgetId) {
   700→      const first = widgets[0];
   701→      if (first) {
   702→        blurAndSetFocus(first.id, first.type);
   703→      }
   704→      return;
   705→    }
   706→
   707→    const currentIndex = widgets.findIndex(w => w.id === focusedWidgetId);
   708→    if (currentIndex === -1) {
   709→      const first = widgets[0];
   710→      if (first) {
   711→        blurAndSetFocus(first.id, first.type);
   712→      }
   713→      return;
   714→    }
   715→
   716→    // Simple navigation: up/left = previous, down/right = next
   717→    let nextIndex = currentIndex;
   718→    if (direction === 'up' || direction === 'left') {
   719→      nextIndex = currentIndex > 0 ? currentIndex - 1 : widgets.length - 1;
   720→    } else {
   721→      nextIndex = currentIndex < widgets.length - 1 ? currentIndex + 1 : 0;
   722→    }
   723→
   724→    const nextWidget = widgets[nextIndex];
   725→    if (nextWidget) {
   726→      blurAndSetFocus(nextWidget.id, nextWidget.type);
   727→    }
   728→  },
   729→
   730→  // Layout tree actions
   731→  setLayoutTree: (tree) => set({ layoutTree: tree }),
   732→
   733→  splitPanel: (panelId, direction, newWidgetId) => {
   734→    const { layoutTree } = get();
   735→    if (!layoutTree) return;
   736→
   737→    // Find the leaf node to split
   738→    const targetNode = findNode(layoutTree, panelId);
   739→    if (!targetNode || targetNode.type !== 'leaf') {
   740→      console.warn('[WorkspaceStore] Cannot split: panel not found or not a leaf');
   741→      return;
   742→    }
   743→
   744→    // Create new leaf for the new agent console
   745→    const newLeaf: LayoutLeaf = {
   746→      type: 'leaf',
   747→      id: generateLayoutId(),
   748→      widgetType: 'agent-console',
   749→      widgetId: newWidgetId,
   750→    };
   751→
   752→    // Create a new group containing the original and new leaf
   753→    const newGroup: LayoutGroup = {
   754→      type: 'group',
   755→      id: generateLayoutId(),
   756→      direction,
   757→      children: [targetNode, newLeaf],
   758→      sizes: [50, 50],
   759→    };
   760→
   761→    // Replace the original leaf with the new group
   762→    const newTree = replaceNode(layoutTree, panelId, newGroup);
   763→    set({ layoutTree: newTree });
   764→  },
   765→
   766→  addPanelToLayout: (options) => {
   767→    const { layoutTree } = get();
   768→    const { widgetType, widgetId } = options;
   769→
   770→    // Create new leaf for the widget
   771→    const newLeaf: LayoutLeaf = {
   772→      type: 'leaf',
   773→      id: generateLayoutId(),
   774→      widgetType,
   775→      widgetId,
   776→    };
   777→
   778→    if (!layoutTree) {
   779→      // No existing layout - create a single leaf as root
   780→      set({ layoutTree: newLeaf });
   781→      return;
   782→    }
   783→
   784→    if (layoutTree.type === 'leaf') {
   785→      // Single leaf - create a horizontal group with the existing and new leaf
   786→      const newGroup: LayoutGroup = {
   787→        type: 'group',
   788→        id: generateLayoutId(),
   789→        direction: 'horizontal',
   790→        children: [layoutTree, newLeaf],
   791→        sizes: [50, 50],
   792→      };
   793→      set({ layoutTree: newGroup });
   794→      return;
   795→    }
   796→
   797→    // Group - add to the end of the top-level group
   798→    const updatedGroup: LayoutGroup = {
   799→      ...layoutTree,
   800→      children: [...layoutTree.children, newLeaf],
   801→      sizes: layoutTree.sizes.map(() => 100 / (layoutTree.children.length + 1))
   802→        .concat([100 / (layoutTree.children.length + 1)]),
   803→    };
   804→    // Normalize sizes to add up to 100
   805→    const total = updatedGroup.sizes.reduce((a, b) => a + b, 0);
   806→    updatedGroup.sizes = updatedGroup.sizes.map(s => (s / total) * 100);
   807→    set({ layoutTree: updatedGroup });
   808→  },
   809→
   810→  closePanelInLayout: (panelId) => {
   811→    const { layoutTree } = get();
   812→    if (!layoutTree) return;
   813→
   814→    const newTree = removeNode(layoutTree, panelId);
   815→    set({ layoutTree: newTree });
   816→  },
   817→
   818→  swapPanels: (panelId1, panelId2) => {
   819→    const { layoutTree } = get();
   820→    if (!layoutTree) return;
   821→
   822→    const node1 = findNode(layoutTree, panelId1);
   823→    const node2 = findNode(layoutTree, panelId2);
   824→
   825→    if (!node1 || !node2 || node1.type !== 'leaf' || node2.type !== 'leaf') {
   826→      console.warn('[WorkspaceStore] Cannot swap: panels not found or not leaves');
   827→      return;
   828→    }
   829→
   830→    // Swap the widget contents but keep the layout node IDs
   831→    const temp1 = { widgetType: node1.widgetType, widgetId: node1.widgetId };
   832→    const temp2 = { widgetType: node2.widgetType, widgetId: node2.widgetId };
   833→
   834→    // Clone and update
   835→    const newTree = cloneTree(layoutTree);
   836→    const newNode1 = findNode(newTree, panelId1) as LayoutLeaf;
   837→    const newNode2 = findNode(newTree, panelId2) as LayoutLeaf;
   838→
   839→    if (newNode1 && newNode2) {
   840→      newNode1.widgetType = temp2.widgetType;
   841→      newNode1.widgetId = temp2.widgetId;
   842→      newNode2.widgetType = temp1.widgetType;
   843→      newNode2.widgetId = temp1.widgetId;
   844→    }
   845→
   846→    set({ layoutTree: newTree });
   847→  },
   848→
   849→  movePanel: (sourcePanelId, targetPanelId, position) => {
   850→    const { layoutTree } = get();
   851→    if (!layoutTree) return;
   852→    if (sourcePanelId === targetPanelId) return;
   853→
   854→    // If position is 'center', just swap the panels
   855→    if (position === 'center') {
   856→      get().swapPanels(sourcePanelId, targetPanelId);
   857→      return;
   858→    }
   859→
   860→    const sourceNode = findNode(layoutTree, sourcePanelId);
   861→    const targetNode = findNode(layoutTree, targetPanelId);
   862→
   863→    if (!sourceNode || !targetNode || sourceNode.type !== 'leaf' || targetNode.type !== 'leaf') {
   864→      console.warn('[WorkspaceStore] Cannot move: panels not found or not leaves');
   865→      return;
   866→    }
   867→
   868→    // Clone the source node with a new ID (it will be inserted at the new location)
   869→    const movedLeaf: LayoutLeaf = {
   870→      type: 'leaf',
   871→      id: generateLayoutId(),
   872→      widgetType: sourceNode.widgetType,
   873→      widgetId: sourceNode.widgetId,
   874→    };
   875→
   876→    // Determine direction based on position
   877→    const direction: 'horizontal' | 'vertical' =
